/* Shared site chrome — header (top tab switcher), hero (logo + slogan),
   and footer. Loaded on every page; injected into .page.

   SINGLE SOURCE OF TRUTH: edit the markup here once and it applies to every
   page. The active tab and the page-specific subtitle are chosen from
   <div class="page" data-page="games"> (or "about").

   Loaded as the first child of .page so it runs before each page's own
   end-of-body script, which expects .logo / .wordmark / the hero to exist. */
(function () {
  var page = document.querySelector('.page');
  if (!page) return;

  // In an installed PWA, skip the hero's entrance animation so the content is
  // fully in place the instant the iOS app-open zoom finishes (no extra
  // fade/slide on top of the launch = clean start). Browser tabs keep it.
  if (navigator.standalone || (window.matchMedia && matchMedia('(display-mode: standalone)').matches)) {
    document.documentElement.classList.add('standalone');
  }
  var active = (page.getAttribute('data-page') || '').toLowerCase();
  var on = function (name) { return active === name ? ' on' : ''; };

  // Subtitle shown under the slogan, per page. Edit here once — applies everywhere.
  var SUBTITLE = {
games: 'Indie gems, top releases, hidden hits.<br>Short. Direct. Smart.<br>Use tags &gt; pick a game &gt; play better.',
about: 'Indie gems, top releases, hidden hits.<br>Short. Direct. Smart.<br>Use tags &gt; pick a game &gt; play better.'
  };
  var sub = SUBTITLE[active] ? '<p>' + SUBTITLE[active] + '</p>' : '';

  page.insertAdjacentHTML('afterbegin',
    '<header>' +
      '<a class="wordmark" href="/">' +
        'hexplay<span style="color:var(--cyan)">_</span>' +
      '</a>' +
      '<nav class="nav">' +
        '<a href="/" class="nav-btn' + on('games') + '"><svg class="nav-ic" viewBox="0 0 24 24" aria-hidden="true"><circle cx="12" cy="6" r="3"/><path d="M12 9v6"/><path d="M6 15h12a2 2 0 0 1 2 2v2a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2v-2a2 2 0 0 1 2-2Z"/></svg>games</a>' +
        '<a href="/about" class="nav-btn' + on('about') + '"><svg class="nav-ic" viewBox="0 0 24 24" aria-hidden="true"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4"/><path d="M12 8h.01"/></svg>about</a>' +
      '</nav>' +
    '</header>' +
    '<section class="hero">' +
      '<div class="logo-wrap"><img class="logo" src="data:image/jpeg;base64," alt="hexplay — curated mobile games" width="600" height="600" decoding="async" fetchpriority="high" draggable="false"></div>' +
      '<div class="hero-text">' +
        '<div class="hero-eyebrow">// catalog of the best mobile games</div>' +
        '<h1>I filter the noise<br><span class="grad">You play better</span></h1>' +
        sub +
      '</div>' +
    '</section>'
  );

  // Footer must land at the very end of .page. This script runs as the first
  // child, so at this point the rest of the page body isn't parsed yet — a
  // synchronous beforeend would drop the footer above the page content. Defer
  // it until the DOM is ready so it's appended after everything. (The header +
  // hero stay synchronous because each page's end-of-body script needs them.)
  var addFooter = function () {
    page.insertAdjacentHTML('beforeend',
      '<footer>' +
        '<span class="footer-mark legal" style="flex-basis:100%;font-weight:400;color:var(--dim)!important">hexplay doesn&#39;t track you or collect your data · all rights belong to their owners</span>' +
        '<style>footer .fs{display:inline-flex;align-items:center;gap:7px;text-decoration:none;font-family:"Space Mono",ui-monospace,\'Courier New\',monospace;font-size:14px;font-weight:700;letter-spacing:0.05em;text-transform:lowercase;transition:color 0.15s,transform 0.12s}footer .fs svg{width:14px;height:14px;fill:currentColor;flex-shrink:0}footer .fs{color:#57b487}footer .fs:active{transform:scale(0.95);color:#79e8a8}@media(hover:hover){footer .fs:hover{color:#79e8a8}}</style><span class="footer-mark" style="flex-basis:100%;font-weight:400;display:flex;justify-content:center;align-items:center;gap:22px;flex-wrap:wrap;margin-top:-12px;margin-bottom:7px"><a class="fs tg" href="https://t.me/hexplay" target="_blank" rel="noopener"><svg style="width:14px;height:14px;fill:currentColor;flex-shrink:0" viewBox="0 0 24 24" aria-hidden="true"><path d="M11.944 0A12 12 0 0 0 0 12a12 12 0 0 0 12 12 12 12 0 0 0 12-12A12 12 0 0 0 12 0a12 12 0 0 0-.056 0zm4.962 7.224c.1-.002.321.023.465.14a.506.506 0 0 1 .171.325c.016.093.036.306.02.472-.18 1.898-.962 6.502-1.36 8.627-.168.9-.499 1.201-.82 1.23-.696.065-1.225-.46-1.9-.902-1.056-.693-1.653-1.124-2.678-1.8-1.185-.78-.417-1.21.258-1.91.177-.184 3.247-2.977 3.307-3.23.007-.032.014-.15-.056-.212s-.174-.041-.249-.024c-.106.024-1.793 1.14-5.061 3.345-.48.33-.913.49-1.302.48-.428-.008-1.252-.241-1.865-.44-.752-.245-1.349-.374-1.297-.789.027-.216.325-.437.893-.663 3.498-1.524 5.83-2.529 6.998-3.014 3.332-1.386 4.025-1.627 4.476-1.635z"/></svg>telegram</a><a class="fs th" href="https://www.threads.com/@hexplay.games" target="_blank" rel="noopener"><svg style="width:14px;height:14px;fill:currentColor;flex-shrink:0" viewBox="0 0 24 24" aria-hidden="true"><path d="M12.186 24h-.007c-3.581-.024-6.334-1.205-8.184-3.509C2.35 18.44 1.5 15.586 1.472 12.01v-.017c.03-3.579.879-6.43 2.525-8.482C5.845 1.205 8.6.024 12.18 0h.014c2.746.02 5.043.725 6.826 2.098 1.677 1.29 2.858 3.13 3.509 5.467l-2.04.569c-1.104-3.96-3.898-5.984-8.304-6.015-2.91.022-5.11.936-6.54 2.717C4.307 6.504 3.616 8.914 3.589 12c.027 3.086.718 5.496 2.057 7.164 1.43 1.783 3.631 2.698 6.54 2.717 2.623-.02 4.358-.631 5.8-2.045 1.647-1.613 1.618-3.593 1.09-4.798-.31-.71-.873-1.3-1.634-1.75-.192 1.352-.622 2.446-1.284 3.272-.886 1.102-2.14 1.704-3.73 1.79-1.202.065-2.361-.218-3.259-.801-1.063-.689-1.685-1.74-1.752-2.964-.065-1.19.408-2.285 1.33-3.082.88-.76 2.119-1.207 3.583-1.291a13.853 13.853 0 0 1 3.02.142c-.126-.742-.375-1.332-.75-1.757-.513-.586-1.308-.883-2.359-.89h-.029c-.844 0-1.992.232-2.721 1.32L7.734 7.847c.98-1.454 2.568-2.256 4.478-2.256h.044c3.194.02 5.097 1.975 5.287 5.388.108.046.216.094.321.142 1.49.7 2.58 1.761 3.154 3.07.797 1.82.871 4.79-1.548 7.158-1.85 1.81-4.094 2.628-7.277 2.65Zm1.003-11.69c-.242 0-.487.007-.739.021-1.836.103-2.98.946-2.916 2.143.067 1.256 1.452 1.839 2.784 1.767 1.224-.065 2.818-.543 3.086-3.71a10.5 10.5 0 0 0-2.215-.221z"/></svg>threads</a><a class="fs bs" href="https://bsky.app/profile/hexplay.bsky.social" target="_blank" rel="noopener"><svg style="width:14px;height:14px;fill:currentColor;flex-shrink:0" viewBox="0 0 24 24" aria-hidden="true"><path d="M12 10.8c-1.087-2.114-4.046-6.053-6.798-7.995C2.566.944 1.561 1.266.902 1.565.139 1.908 0 3.08 0 3.768c0 .69.378 5.65.624 6.479.815 2.736 3.713 3.66 6.383 3.364.136-.02.275-.039.415-.056-.138.022-.276.04-.415.056-3.912.58-7.387 2.005-2.83 7.078 5.013 5.19 6.87-1.113 7.823-4.308.953 3.195 2.05 9.271 7.733 4.308 4.267-4.308 1.172-6.498-2.74-7.078a8.741 8.741 0 0 1-.415-.056c.14.017.279.036.415.056 2.67.297 5.568-.628 6.383-3.364.246-.828.624-5.79.624-6.478 0-.69-.139-1.861-.902-2.206-.659-.298-1.664-.62-4.3 1.24C16.046 4.748 13.087 8.687 12 10.8Z"/></svg>bluesky</a></span>' +
        '<span class="footer-mark">// built by a gamer — for gamers</span>' +
        '<span class="footer-mark">hexplay © 2026</span>' +
      '</footer>'
    );
  };
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', addFooter);
  } else {
    addFooter();
  }
})();
